import{_ as i,c as a,a2 as s,o as t}from"./chunks/framework.CKjLqgBu.js";const g=JSON.parse('{"title":"HADLC Demo: Draggable Windows","description":"","frontmatter":{"head":[]},"headers":[],"relativePath":"plans/2026-02-10-hadlc-draggable-windows-design.md","filePath":"plans/2026-02-10-hadlc-draggable-windows-design.md","lastUpdated":null}'),n={name:"plans/2026-02-10-hadlc-draggable-windows-design.md"};function o(d,e,l,r,p,h){return t(),a("div",null,e[0]||(e[0]=[s('<h1 id="hadlc-demo-draggable-windows" tabindex="-1">HADLC Demo: Draggable Windows <a class="header-anchor" href="#hadlc-demo-draggable-windows" aria-label="Permalink to &quot;HADLC Demo: Draggable Windows&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>Two issues with the current HADLC demo window system:</p><ol><li><p><strong>Teams visibility bug</strong> -- The Teams window (right column) goes out of view after phase 2. The flex grid layout allows content with implicit minimum widths (e.g. <code>whitespace-pre</code> in VS Code, growing API docs in Browser) to squeeze the right column off-screen at certain viewport sizes.</p></li><li><p><strong>Visual realism</strong> -- The rigid 2-row flex grid doesn&#39;t look like a real macOS desktop. Real desktops have overlapping, freely-positioned windows.</p></li></ol><h2 id="solution" tabindex="-1">Solution <a class="header-anchor" href="#solution" aria-label="Permalink to &quot;Solution&quot;">​</a></h2><p>Replace the flex grid layout with absolutely-positioned, draggable, resizable windows. This fixes both issues: absolute positioning means windows can never push each other off-screen, and free positioning looks like a real desktop.</p><h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><ul><li><strong>Static positions, content-only steps</strong> -- The step engine only changes window content, not positions. Users can manually drag/resize windows during the presentation.</li><li><strong>Active window auto-raises</strong> -- When the step engine changes <code>activeWindow</code>, that window&#39;s z-index is bumped to bring it to front.</li><li><strong>Percentage-based coordinates</strong> -- All positions and sizes are expressed as percentages of the desktop container, so the layout scales across viewport sizes.</li></ul><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><h3 id="new-usewindowmanager-ts-composable" tabindex="-1">New: <code>useWindowManager.ts</code> composable <a class="header-anchor" href="#new-usewindowmanager-ts-composable" aria-label="Permalink to &quot;New: `useWindowManager.ts` composable&quot;">​</a></h3><p>Manages reactive state for all 5 windows:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> WindowGeometry</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  x</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // % from left</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  y</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // % from top</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  w</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // % width</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  h</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // % height</span></span>\n<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  zIndex</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Initial positions (matching real desktop screenshot):</p><table tabindex="0"><thead><tr><th>Window</th><th>x</th><th>y</th><th>w</th><th>h</th></tr></thead><tbody><tr><td>browser</td><td>1</td><td>1</td><td>33</td><td>48</td></tr><tr><td>claude</td><td>35</td><td>1</td><td>33</td><td>48</td></tr><tr><td>vscode</td><td>1</td><td>51</td><td>42</td><td>48</td></tr><tr><td>finder</td><td>44</td><td>51</td><td>24</td><td>48</td></tr><tr><td>teams</td><td>69</td><td>1</td><td>30</td><td>98</td></tr></tbody></table><p>Three functions:</p><ul><li><code>startDrag(windowId, pointerEvent)</code> -- Title bar drag. Converts pixel deltas to percentage offsets. Clamps to keep at least 50px visible.</li><li><code>startResize(windowId, edge, pointerEvent)</code> -- Edge/corner resize. Enforces minimum 15% width, 15% height.</li><li><code>bringToFront(windowId)</code> -- Increments global z-counter and assigns to window.</li></ul><p>Requires a template ref to the desktop container for pixel-to-percentage conversion.</p><h3 id="modified-window-vue" tabindex="-1">Modified: <code>Window.vue</code> <a class="header-anchor" href="#modified-window-vue" aria-label="Permalink to &quot;Modified: `Window.vue`&quot;">​</a></h3><p>New behaviors added to existing component:</p><ul><li><strong>Title bar drag</strong>: <code>@pointerdown</code> on title bar calls <code>startDrag</code>.</li><li><strong>Resize handles</strong>: 8 invisible hit zones (N, S, E, W, NE, NW, SE, SW) positioned absolutely around window edges. 6px wide on edges, 12x12px on corners. Transparent with appropriate cursor styles.</li><li><strong>Z-order on click</strong>: <code>@pointerdown</code> on entire window calls <code>bringToFront</code>.</li></ul><p>New props: <code>windowId</code>, <code>manager</code> (the window manager composable).</p><h3 id="modified-app-vue" tabindex="-1">Modified: <code>App.vue</code> <a class="header-anchor" href="#modified-app-vue" aria-label="Permalink to &quot;Modified: `App.vue`&quot;">​</a></h3><p>The nested flex grid is replaced with a flat list of absolutely-positioned windows inside a <code>position: relative</code> desktop container:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MenuBar (flex, top)</span></span>\n<span class="line"><span>Desktop (flex-1, relative) &lt;-- windows live here as absolute children</span></span>\n<span class="line"><span>Dock (flex, bottom)</span></span></code></pre></div><h3 id="modified-usestepengine-ts" tabindex="-1">Modified: <code>useStepEngine.ts</code> <a class="header-anchor" href="#modified-usestepengine-ts" aria-label="Permalink to &quot;Modified: `useStepEngine.ts`&quot;">​</a></h3><p>When <code>activeWindow</code> changes, calls <code>windowManager.bringToFront(windowId)</code> to auto-raise the relevant window.</p><h3 id="unchanged" tabindex="-1">Unchanged <a class="header-anchor" href="#unchanged" aria-label="Permalink to &quot;Unchanged&quot;">​</a></h3><ul><li>All app components (TeamsApp, BrowserApp, VscodeApp, ClaudeCodeApp, FinderApp) -- no changes needed</li><li>MenuBar, Dock -- stay in flex flow above/below the desktop</li><li>Scenario data -- no new fields needed</li><li>Style/animations -- glow animation and message animations stay as-is</li></ul><h2 id="implementation-order" tabindex="-1">Implementation Order <a class="header-anchor" href="#implementation-order" aria-label="Permalink to &quot;Implementation Order&quot;">​</a></h2><ol><li>Create <code>useWindowManager.ts</code> composable</li><li>Update <code>Window.vue</code> with drag, resize, and z-order behaviors</li><li>Update <code>App.vue</code> to use absolute positioning with window manager</li><li>Wire <code>useStepEngine.ts</code> to call <code>bringToFront</code> on active window change</li><li>Test at multiple viewport sizes to verify Teams stays visible</li></ol>',30)]))}const w=i(n,[["render",o]]);export{g as __pageData,w as default};
